namespace UniversityCourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Name { get; set; } = "";
    public string Code { get; set; } = "";
    public string Description { get; set; } = "";
}

public class Course
{
    public int Id { get; set; }
    public int DepartmentId { get; set; }
    public string DepartmentCode { get; set; } = "";
    public string DepartmentName { get; set; } = "";
    public string CourseNumber { get; set; } = "";
    public string Title { get; set; } = "";
    public string Description { get; set; } = "";
    public int Credits { get; set; }
    public string Schedule { get; set; } = "";
    public string InstructorName { get; set; } = "";
    public string InstructorBio { get; set; } = "";
    public bool IsFeatured { get; set; }
}

public class EnrollmentRequest
{
    public string StudentName { get; set; } = "";
    public string StudentId { get; set; } = "";
    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Course> _courses;
    private readonly List<EnrollmentRequest> _enrollments = new();

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Name = "Computer Science", Code = "CS", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Name = "Mathematics", Code = "MATH", Description = "Study of numbers, structures, and patterns." },
            new() { Id = 3, Name = "English", Code = "ENG", Description = "Study of literature, writing, and language." },
            new() { Id = 4, Name = "Physics", Code = "PHYS", Description = "Study of matter, energy, and the fundamental forces of nature." }
        };

        _courses = new List<Course>
        {
            // Computer Science
            new() { Id = 1, DepartmentId = 1, DepartmentCode = "CS", DepartmentName = "Computer Science", CourseNumber = "101", Title = "Introduction to Programming", Description = "Learn the fundamentals of programming using Python. Topics include variables, control flow, functions, and basic data structures.", Credits = 3, Schedule = "MWF 9:00-9:50 AM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen has 15 years of experience teaching introductory programming and has authored two textbooks on Python.", IsFeatured = true },
            new() { Id = 2, DepartmentId = 1, DepartmentCode = "CS", DepartmentName = "Computer Science", CourseNumber = "201", Title = "Data Structures and Algorithms", Description = "Study of fundamental data structures including arrays, linked lists, trees, and graphs. Algorithm analysis and design techniques.", Credits = 4, Schedule = "TTh 10:30-11:50 AM", InstructorName = "Dr. James Martinez", InstructorBio = "Dr. Martinez specializes in algorithm optimization and has published extensively in computational complexity theory.", IsFeatured = false },
            new() { Id = 3, DepartmentId = 1, DepartmentCode = "CS", DepartmentName = "Computer Science", CourseNumber = "310", Title = "Software Engineering", Description = "Principles of software development including design patterns, testing, version control, and agile methodologies.", Credits = 3, Schedule = "MWF 1:00-1:50 PM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen has 15 years of experience teaching introductory programming and has authored two textbooks on Python.", IsFeatured = true },

            // Mathematics
            new() { Id = 4, DepartmentId = 2, DepartmentCode = "MATH", DepartmentName = "Mathematics", CourseNumber = "101", Title = "Calculus I", Description = "Introduction to differential calculus. Topics include limits, derivatives, and applications of differentiation.", Credits = 4, Schedule = "MWF 8:00-8:50 AM", InstructorName = "Dr. Robert Kim", InstructorBio = "Dr. Kim is an award-winning educator with a passion for making calculus accessible to all students.", IsFeatured = true },
            new() { Id = 5, DepartmentId = 2, DepartmentCode = "MATH", DepartmentName = "Mathematics", CourseNumber = "201", Title = "Linear Algebra", Description = "Study of vector spaces, linear transformations, matrices, and eigenvalues.", Credits = 3, Schedule = "TTh 9:00-10:20 AM", InstructorName = "Dr. Lisa Park", InstructorBio = "Dr. Park's research focuses on applied linear algebra in machine learning and data science.", IsFeatured = false },
            new() { Id = 6, DepartmentId = 2, DepartmentCode = "MATH", DepartmentName = "Mathematics", CourseNumber = "301", Title = "Differential Equations", Description = "Ordinary differential equations, systems of equations, Laplace transforms, and numerical methods.", Credits = 3, Schedule = "MWF 11:00-11:50 AM", InstructorName = "Dr. Robert Kim", InstructorBio = "Dr. Kim is an award-winning educator with a passion for making calculus accessible to all students.", IsFeatured = false },

            // English
            new() { Id = 7, DepartmentId = 3, DepartmentCode = "ENG", DepartmentName = "English", CourseNumber = "101", Title = "Composition and Rhetoric", Description = "Develop skills in academic writing, critical thinking, and argumentation.", Credits = 3, Schedule = "MWF 10:00-10:50 AM", InstructorName = "Prof. Amanda Hughes", InstructorBio = "Prof. Hughes is a published author and writing consultant with expertise in rhetoric and composition pedagogy.", IsFeatured = false },
            new() { Id = 8, DepartmentId = 3, DepartmentCode = "ENG", DepartmentName = "English", CourseNumber = "220", Title = "American Literature", Description = "Survey of American literature from the colonial period to the present day.", Credits = 3, Schedule = "TTh 1:00-2:20 PM", InstructorName = "Dr. Michael Torres", InstructorBio = "Dr. Torres specializes in 20th century American fiction and has published three books on the subject.", IsFeatured = true },
            new() { Id = 9, DepartmentId = 3, DepartmentCode = "ENG", DepartmentName = "English", CourseNumber = "315", Title = "Creative Writing Workshop", Description = "Workshop-based course focusing on fiction and poetry writing with peer critique.", Credits = 3, Schedule = "W 3:00-5:50 PM", InstructorName = "Prof. Amanda Hughes", InstructorBio = "Prof. Hughes is a published author and writing consultant with expertise in rhetoric and composition pedagogy.", IsFeatured = false },

            // Physics
            new() { Id = 10, DepartmentId = 4, DepartmentCode = "PHYS", DepartmentName = "Physics", CourseNumber = "101", Title = "General Physics I", Description = "Mechanics, waves, and thermodynamics. Calculus-based introduction to classical physics.", Credits = 4, Schedule = "MWF 9:00-9:50 AM", InstructorName = "Dr. Elena Volkov", InstructorBio = "Dr. Volkov is a former NASA researcher with expertise in astrophysics and classical mechanics.", IsFeatured = false },
            new() { Id = 11, DepartmentId = 4, DepartmentCode = "PHYS", DepartmentName = "Physics", CourseNumber = "201", Title = "General Physics II", Description = "Electricity, magnetism, optics, and modern physics.", Credits = 4, Schedule = "TTh 10:30-11:50 AM", InstructorName = "Dr. Elena Volkov", InstructorBio = "Dr. Volkov is a former NASA researcher with expertise in astrophysics and classical mechanics.", IsFeatured = false },
            new() { Id = 12, DepartmentId = 4, DepartmentCode = "PHYS", DepartmentName = "Physics", CourseNumber = "310", Title = "Quantum Mechanics", Description = "Introduction to quantum theory, wave functions, Schr├╢dinger equation, and applications.", Credits = 3, Schedule = "MWF 2:00-2:50 PM", InstructorName = "Dr. David Nakamura", InstructorBio = "Dr. Nakamura conducts research in quantum computing and has contributed to several breakthrough papers.", IsFeatured = true }
        };
    }

    public List<Department> GetDepartments() => _departments;

    public List<Course> GetCourses(string? search, string? departmentCode)
    {
        var query = _courses.AsEnumerable();

        if (!string.IsNullOrWhiteSpace(departmentCode))
        {
            query = query.Where(c => c.DepartmentCode.Equals(departmentCode, StringComparison.OrdinalIgnoreCase));
        }

        if (!string.IsNullOrWhiteSpace(search))
        {
            query = query.Where(c =>
                c.Title.Contains(search, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(search, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(search, StringComparison.OrdinalIgnoreCase) ||
                $"{c.DepartmentCode} {c.CourseNumber}".Contains(search, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public bool SubmitEnrollment(EnrollmentRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.StudentName) ||
            string.IsNullOrWhiteSpace(request.StudentId) ||
            request.CourseId <= 0)
        {
            return false;
        }

        var course = GetCourse(request.CourseId);
        if (course == null) return false;

        _enrollments.Add(request);
        return true;
    }
}

