@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService CatalogService

<PageTitle>Enroll - University Course Catalog</PageTitle>

<h1>Course Enrollment</h1>

@if (submitted)
{
    <div class="alert alert-success">
        <h4>Enrollment Submitted!</h4>
        <p>Thank you, <strong>@Model.StudentName</strong>. Your enrollment request for <strong>@enrolledCourseName</strong> has been received.</p>
    </div>
    <a href="/courses" class="btn btn-primary">Browse More Courses</a>
}
else
{
    <form method="post" class="mt-3">
        <AntiforgeryToken />

        <div class="mb-3">
            <label for="studentName" class="form-label">Student Name</label>
            <input type="text" class="form-control" id="studentName" name="Model.StudentName" value="@Model.StudentName" required />
