        <div class="mb-3">
            <label for="studentId" class="form-label">Student ID</label>
            <input type="text" class="form-control" id="studentId" name="Model.StudentId" value="@Model.StudentId" required />
        </div>

        <div class="mb-3">
            <label for="courseId" class="form-label">Course</label>
            <select class="form-select" id="courseId" name="Model.CourseId" required>
                <option value="">Select a course...</option>
                @foreach (var course in courses)
                {
                    <option value="@course.Id" selected="@(Model.CourseId == course.Id)">@course.DepartmentCode @course.CourseNumber - @course.Title</option>
                }
            </select>
        </div>

        <button type="submit" class="btn btn-success">Submit Enrollment</button>
    </form>
}

@code {
    [SupplyParameterFromQuery]
    public int? CourseId { get; set; }

    [SupplyParameterFromForm]
    public EnrollmentRequest Model { get; set; } = new();

    private List<Course> courses = new();
    private bool submitted;
    private string enrolledCourseName = "";

    protected override void OnInitialized()
    {
        courses = CatalogService.GetCourses(null, null);

        if (CourseId.HasValue && Model.CourseId == 0)
        {
            Model.CourseId = CourseId.Value;
        }

        if (Model.CourseId > 0 && !string.IsNullOrWhiteSpace(Model.StudentName))
        {
            var course = CatalogService.GetCourse(Model.CourseId);
            if (course != null)
            {
                enrolledCourseName = $"{course.DepartmentCode} {course.CourseNumber} - {course.Title}";
                submitted = CatalogService.SubmitEnrollment(Model);
            }
        }
    }
}

